{"path":"app/frontend/app.js","content":"document.addEventListener('DOMContentLoaded', () => {
    // Update current date in header
    const headerDateElement = document.querySelector('.header-date');
    if (headerDateElement) {
        const today = new Date();
        const options = { year: 'numeric', month: 'long', day: 'numeric' };
        headerDateElement.textContent = `Today, ${today.toLocaleDateString(undefined, options)}`;
    }

    // Protocol completion toggle
    const protocolCheckboxes = document.querySelectorAll('.protocol-checkbox input[type="checkbox"]');
    protocolCheckboxes.forEach(checkbox => {
        checkbox.addEventListener('change', (event) => {
            const protocolItem = event.target.closest('.protocol-item');
            if (protocolItem) {
                if (event.target.checked) {
                    protocolItem.classList.add('completed');
                    console.log(`Protocol item ${protocolItem.dataset.protocolId} completed.`);
                } else {
                    protocolItem.classList.remove('completed');
                    console.log(`Protocol item ${protocolItem.dataset.protocolId} marked incomplete.`);
                }
            }
        });
    });

    // Progress check-in functionality
    const checkinButtons = document.querySelectorAll('.checkin-button');
    const checkinFeedback = document.getElementById('checkin-feedback');

    checkinButtons.forEach(button => {
        button.addEventListener('click', () => {
            // Remove 'selected' class from all buttons
            checkinButtons.forEach(btn => btn.classList.remove('selected'));

            // Add 'selected' class to the clicked button
            button.classList.add('selected');

            // Provide feedback
            const mood = button.dataset.checkinMood;
            let feedbackText = '';
            switch(mood) {
                case 'great':
                    feedbackText = 'Wonderful! Keep that energy flowing.';
                    break;
                case 'good':
                    feedbackText = 'Glad to hear! Keep nurturing your well-being.';
                    break;
                case 'okay':
                    feedbackText = 'Understanding your current state is powerful. We're here for you.';
                    break;
                case 'challenging':
                    feedbackText = 'It's okay to have challenging moments. Duey is here to help.';
                    break;
                default:
                    feedbackText = 'Thank you for checking in!';
            }
            checkinFeedback.textContent = feedbackText;
            console.log(`Checked in with mood: ${mood}`);
        });
    });

    // Initialize current year in footer
    const footerElement = document.querySelector('.dashboard-footer p');
    if (footerElement) {
        const currentYear = new Date().getFullYear();
        footerElement.innerHTML = `&copy; ${currentYear} Natural Nation. All rights reserved.`;
    }
});
