{"path":"app/frontend/tests/validate-foundation.mjs","content":"import { promises as fs } from 'fs';
import path from 'path';

const rootDir = path.resolve(path.dirname(new URL(import.meta.url).pathname), '..');

const filesToValidate = [
    { path: 'index.html', requiredContent: [
        /<meta name="viewport"[^>]*initial-scale=1\.0[^>]*>/,
        /<title>Natural Nation - Day 1 Dashboard<\/title>/,
        /<h1>Welcome to Your Natural Nation Journey!<\/h1>/,
        /I'm Duey, your AI wellness mentor/,
        /<h3>Wellness Score<\/h3>/,
        /<h3>Rejuvenation Score<\/h3>/,
        /<h2>Your Daily Protocol Timeline<\/h2>/,
        /class="protocol-item"[^>]*>\s*<span class="protocol-time"[^>]*>\d{1,2}:\d{2} [AP]M<\/span>/,
        /<h2>Your Progress Check-in<\/h2>/,
        /<button class="checkin-button"[^>]*>Great<\/button>/,
        /<script src="app\.js"><\/script>/,
        /<link rel="stylesheet" href="styles\.css">/
    ]},
    { path: 'styles.css', requiredContent: [
        /body\s*\{/,
        /@media \(min-width: 600px\)/,
        /@media \(min-width: 1024px\)/,
        /.dashboard-container/,
        /.duey-intro/,
        /.score-card/,
        /.daily-protocol/,
        /.progress-checkin/,
        /.checkin-button/
    ]},
    { path: 'app.js', requiredContent: [
        /document\.addEventListener\('DOMContentLoaded', \(\) => \{/,
        /const headerDateElement = document\.querySelector\('\.header-date'\);/,
        /const protocolCheckboxes = document\.querySelectorAll\('\.protocol-checkbox input\[type="checkbox"\]'\);/,
        /protocolCheckboxes\.forEach\(checkbox => \{/,
        /const checkinButtons = document\.querySelectorAll\('\.checkin-button'\);/,
        /checkinButtons\.forEach\(button => \{/,
        /const footerElement = document\.querySelector\('\.dashboard-footer p'\);/
    ]},
    { path: 'README.md', requiredContent: [
        /# Natural Nation - Day 1 Member Foundation \(MVP Slice\)/,
        /This directory \(`app\/frontend\/`\) contains the initial static web foundation/,
        /Key Features Demonstrated:/,
        /How to View Locally:/,
        /To run the provided validation script:/,
        /Duey - AI Wellness Mentor:/,
        /Wellness and Rejuvenation Scores:/,
        /Daily Protocol Timeline:/,
        /Progress Check-in Controls:/,
        /Non-Medical Language:/
    ]},
];

async function validateFile(filePath, contentChecks) {
    try {
        const fullPath = path.join(rootDir, filePath);
        const fileContent = await fs.readFile(fullPath, 'utf8');
        console.log(`
Validating: ${filePath}`);

        let allChecksPassed = true;
        for (const check of contentChecks) {
            if (check instanceof RegExp) {
                if (!check.test(fileContent)) {
                    console.error(`  FAIL: Missing regex pattern: ${check}`);
                    allChecksPassed = false;
                } else {
                    console.log(`  PASS: Found regex pattern: ${check}`);
                }
            } else if (typeof check === 'string') {
                if (!fileContent.includes(check)) {
                    console.error(`  FAIL: Missing string: "${check}"`);
                    allChecksPassed = false;
                } else {
                    console.log(`  PASS: Found string: "${check}"`);
                }
            } else {
                console.error(`  ERROR: Invalid check type for ${filePath}`);
                allChecksPassed = false;
            }
        }
        return allChecksPassed;
    } catch (error) {
        console.error(`
ERROR: Could not read or validate ${filePath}: ${error.message}`);
        return false;
    }
}

async function runValidation() {
    let overallSuccess = true;

    for (const file of filesToValidate) {
        const fileSuccess = await validateFile(file.path, file.requiredContent);
        if (!fileSuccess) {
            overallSuccess = false;
        }
    }

    if (overallSuccess) {
        console.log(`
[32m✅ All foundation files validated successfully![0m`);
        process.exit(0);
    } else {
        console.error(`
[31m❌ Foundation validation failed. Please check the errors above.[0m`);
        process.exit(1);
    }
}

runValidation();
"}]}
